mapper.select:
SELECT a.id, a.project_id AS "projectId", d.id AS "detailId", d.version, d.architecture_attachments AS "architectureAttachments", d.structure_attachments AS "structureAttachments", d.decoration_attachments AS "decorationAttachments", d.procurement_attachments AS "procurementAttachments", d.solution_explanation AS "solutionExplanation", d.confirm_members AS "confirmMembers", a.status, a.created_by AS "createdBy", a.updated_by AS "updatedBy", a.created_at AS "createdAt", a.updated_at AS "updatedAt", p.code AS "projectCode", p.name AS "projectName", creator.name AS "createdByName", updater.name AS "updatedByName", CASE a.status WHEN 1 THEN '待提交' WHEN 2 THEN '待确认' WHEN 3 THEN '已归档' ELSE '' END AS "statusText" FROM construction_drawing a LEFT JOIN construction_drawing_detail d ON d.construction_drawing_id = a.id AND d.version = (SELECT MAX(cd.version) FROM construction_drawing_detail cd WHERE cd.construction_drawing_id = a.id) LEFT JOIN project p ON p.id = a.project_id LEFT JOIN sys_account creator ON creator.id = a.created_by LEFT JOIN sys_account updater ON updater.id = a.updated_by
AND a.project_id = #{params.projectId}
AND p.name LIKE CONCAT('%', #{params.projectName}, '%') AND p.name LIKE '%' || #{params.projectName} || '%'
AND a.status = #{params.status}
ORDER BY a.updated_at DESC, a.id DESC
